    /********************************************************
                        Live State Getters
    ********************************************************/

    /// @inheritdoc IReClammPool
    function computeCurrentPriceRange() external view returns (uint256 minPrice, uint256 maxPrice) {
        if (_vault.isPoolInitialized(address(this))) {
            (
                uint256[] memory balancesScaled18,
                uint256 currentVirtualBalanceA,
                uint256 currentVirtualBalanceB,

            ) = _getRealAndVirtualBalances();

            (minPrice, maxPrice) = ReClammMath.computePriceRange(
                balancesScaled18,
                currentVirtualBalanceA,
                currentVirtualBalanceB
            );
        } else {
            minPrice = _INITIAL_MIN_PRICE;
            maxPrice = _INITIAL_MAX_PRICE;
        }
    }

    /// @inheritdoc IReClammPool
    function computeCurrentVirtualBalances()
        external
        view
        onlyWhenInitialized
        returns (uint256 currentVirtualBalanceA, uint256 currentVirtualBalanceB, bool changed)
    {
        (, currentVirtualBalanceA, currentVirtualBalanceB, changed) = _getRealAndVirtualBalances();
    }

    /**
     * @notice Returns current live pool balances and time-adjusted virtual balances.
     * @dev Both balances and virtual balances are in the same underlying/rate-scaled space, which is required
     * for consistent spot price and price ratio calculations. State-mutating paths (onSwap, _updateVirtualBalances)
     * also operate on live balances, so this keeps the frames consistent.
     *
     * @return balancesScaled18 Current live balances, scaled to 18 decimals (decimal scaling and rates applied)
     * @return currentVirtualBalanceA Current virtual balance of token A, adjusted for time elapsed since last update
     * @return currentVirtualBalanceB Current virtual balance of token B, adjusted for time elapsed since last update
     * @return changed True if the virtual balances differ from `lastVirtualBalances`
     */
    function _getRealAndVirtualBalances()
        internal
        view
        returns (
            uint256[] memory balancesScaled18,
            uint256 currentVirtualBalanceA,
            uint256 currentVirtualBalanceB,
            bool changed
        )
    {
        balancesScaled18 = _vault.getCurrentLiveBalances(address(this));
        (currentVirtualBalanceA, currentVirtualBalanceB, changed) = _computeCurrentVirtualBalances(balancesScaled18);
    }

    /// @inheritdoc IReClammPool
    function computeCurrentPriceRatio() external view onlyWhenInitialized returns (uint256) {
        return _computeCurrentPriceRatio();
    }

    /// @inheritdoc IReClammPool
    function computeCurrentFourthRootPriceRatio() external view onlyWhenInitialized returns (uint256) {
        return ReClammMath.fourthRootScaled18(_computeCurrentPriceRatio());
    }

    /// @inheritdoc IReClammPool
    function computeCurrentPoolCenteredness() external view onlyWhenInitialized returns (uint256, bool) {
        (
            uint256[] memory balancesScaled18,
            uint256 currentVirtualBalanceA,
            uint256 currentVirtualBalanceB,

        ) = _getRealAndVirtualBalances();

        return ReClammMath.computeCenteredness(balancesScaled18, currentVirtualBalanceA, currentVirtualBalanceB);
    }

    /// @inheritdoc IReClammPool
    function isPoolWithinTargetRange() external view onlyWhenInitialized returns (bool) {
        (
            uint256[] memory balancesScaled18,
            uint256 currentVirtualBalanceA,
            uint256 currentVirtualBalanceB,

        ) = _getRealAndVirtualBalances();

        return
            ReClammMath.isPoolWithinTargetRange(
                balancesScaled18,
                currentVirtualBalanceA,
                currentVirtualBalanceB,
                _centerednessMargin
            );
    }

    /********************************************************
                        Off-chain Helpers
    ********************************************************/

    /// @inheritdoc IReClammPool
    function computeInitialBalancesRaw(
        IERC20 referenceToken,
        uint256 referenceAmountInRaw
    ) external view returns (uint256[] memory initialBalancesRaw) {
        return _helper.computeInitialBalancesRaw(this, referenceToken, referenceAmountInRaw);
    }

    /// @inheritdoc IReClammPool
    function getReClammPoolDynamicData() external view returns (ReClammPoolDynamicData memory data) {
        data.balancesLiveScaled18 = _vault.getCurrentLiveBalances(address(this));
        (, data.tokenRates) = _vault.getPoolTokenRates(address(this));
        data.staticSwapFeePercentage = _vault.getStaticSwapFeePercentage((address(this)));
        data.totalSupply = totalSupply();

        data.lastTimestamp = _lastTimestamp;
        data.lastVirtualBalances = _getLastVirtualBalances();
        data.dailyPriceShiftBase = _dailyPriceShiftBase;
        data.dailyPriceShiftExponent = data.dailyPriceShiftBase.toDailyPriceShiftExponent();
        data.centerednessMargin = _centerednessMargin;

        PriceRatioState memory state = _priceRatioState;
        data.startFourthRootPriceRatio = state.startFourthRootPriceRatio;
        data.endFourthRootPriceRatio = state.endFourthRootPriceRatio;
        data.priceRatioUpdateStartTime = state.priceRatioUpdateStartTime;
        data.priceRatioUpdateEndTime = state.priceRatioUpdateEndTime;

        PoolConfig memory poolConfig = _vault.getPoolConfig(address(this));
        data.isPoolInitialized = poolConfig.isPoolInitialized;
        data.isPoolPaused = poolConfig.isPoolPaused;
        data.isPoolInRecoveryMode = poolConfig.isPoolInRecoveryMode;

        // The price ratio is derived from live + virtual balances; before initialization, virtual balances are zero
        // and `_computeCurrentPriceRatio` would revert (the public `computeCurrentPriceRatio` getter explicitly
        // reverts with `PoolNotInitialized` for the same reason). Skip the computation here so that integrations
        // can still call `getReClammPoolDynamicData` on a newly deployed pool. The ratio fields stay zero, while
        // the static fields (rates, fees, supply) remain readable.
        if (data.isPoolInitialized) {
            data.currentPriceRatio = _computeCurrentPriceRatio();
            data.currentFourthRootPriceRatio = ReClammMath.fourthRootScaled18(data.currentPriceRatio);
        }
    }

    /// @inheritdoc IReClammPool
    function getReClammPoolImmutableData() external view returns (ReClammPoolImmutableData memory data) {
        // Base Pool
        data.tokens = _vault.getPoolTokens(address(this));
        (data.decimalScalingFactors, ) = _vault.getPoolTokenRates(address(this));
        data.tokenAPriceIncludesRate = _TOKEN_A_PRICE_INCLUDES_RATE;
        data.tokenBPriceIncludesRate = _TOKEN_B_PRICE_INCLUDES_RATE;
        data.minSwapFeePercentage = _MIN_SWAP_FEE_PERCENTAGE;
        data.maxSwapFeePercentage = _MAX_SWAP_FEE_PERCENTAGE;

        // Initialization
        data.initialMinPrice = _INITIAL_MIN_PRICE;
        data.initialMaxPrice = _INITIAL_MAX_PRICE;
        data.initialTargetPrice = _INITIAL_TARGET_PRICE;
        data.initialDailyPriceShiftExponent = _INITIAL_DAILY_PRICE_SHIFT_EXPONENT;
        data.initialCenterednessMargin = _INITIAL_CENTEREDNESS_MARGIN;

        // Operating Limits
        data.minPriceRatio = ReClammPoolFactoryLib.MIN_PRICE_RATIO;
        data.maxPriceRatio = ReClammPoolFactoryLib.MAX_PRICE_RATIO;
        data.maxCenterednessMargin = ReClammPoolFactoryLib.MAX_CENTEREDNESS_MARGIN;
        data.maxDailyPriceShiftExponent = ReClammPoolFactoryLib.MAX_DAILY_PRICE_SHIFT_EXPONENT;
        data.maxDailyPriceRatioUpdateRate = _MAX_DAILY_PRICE_RATIO_UPDATE_RATE;
        data.minPriceRatioUpdateDuration = _MIN_PRICE_RATIO_UPDATE_DURATION;
        data.minPriceRatioDelta = _MIN_PRICE_RATIO_DELTA;
        data.balanceRatioAndPriceTolerance = _BALANCE_RATIO_AND_PRICE_TOLERANCE;
    }

    /********************************************************
                        Pool State Setters
    ********************************************************/

    // NOTE: `startPriceRatioUpdate` and `stopPriceRatioUpdate` intentionally omit `onlyWhenVaultIsLocked`.
    // See the interface NatSpec for the details.

    /// @inheritdoc IReClammPool
    function startPriceRatioUpdate(
        uint256 endPriceRatio,
        uint256 priceRatioUpdateStartTime,
        uint256 priceRatioUpdateEndTime
    )
        external
        onlyWhenInitialized
        onlySwapFeeManagerOrGovernance(address(this))
        returns (uint256 actualPriceRatioUpdateStartTime)
    {
        // Note: If the initial price range was 1,000 - 4,000, with a target price of 2,000, the raw ratio
        // is 4 (`startPriceRatio` ~ 1.414). If the new fourth root is 1.682, the new `endPriceRatio` is 1.682^4 ~ 8.
        // Since the centeredness remains constant, the new range would NOT be 1,000 - 8,000, but
        // [C / sqrt(8), C * sqrt(8)], or about 707 - 5657.

        if (endPriceRatio < ReClammPoolFactoryLib.MIN_PRICE_RATIO) {
            revert PriceRatioBelowMin(endPriceRatio);
        } else if (endPriceRatio > ReClammPoolFactoryLib.MAX_PRICE_RATIO) {
            revert PriceRatioAboveMax(endPriceRatio);
        }

        actualPriceRatioUpdateStartTime = GradualValueChange.resolveStartTime(
            priceRatioUpdateStartTime,
            priceRatioUpdateEndTime
        );

        uint256 updateDuration = priceRatioUpdateEndTime - actualPriceRatioUpdateStartTime;

        // We've already validated that end time >= start time at this point.
        require(updateDuration >= _MIN_PRICE_RATIO_UPDATE_DURATION, PriceRatioUpdateDurationTooShort());

        uint256[] memory balancesScaled18 = _updateVirtualBalances();

        // Compute the starting price ratio from the balances `_updateVirtualBalances` returned and the virtual
        // balances it wrote. This avoids a second Vault rate fetch within the same transaction and keeps the starting
        // ratio consistent with the inputs that drove the virtual balance update.
        uint256 startPriceRatio = ReClammMath.computePriceRatio(
            balancesScaled18,
            _lastVirtualBalanceA,
            _lastVirtualBalanceB
        );

        _startPriceRatioUpdate(
            endPriceRatio,
            actualPriceRatioUpdateStartTime,
            priceRatioUpdateEndTime,
            startPriceRatio
        );

        uint256 priceRatioDelta;
        unchecked {
            priceRatioDelta = endPriceRatio >= startPriceRatio
                ? endPriceRatio - startPriceRatio
                : startPriceRatio - endPriceRatio;
        }

        require(priceRatioDelta >= _MIN_PRICE_RATIO_DELTA, PriceRatioDeltaBelowMin(priceRatioDelta));

        if (
            _computeDailyPriceRatioUpdateRate(startPriceRatio, endPriceRatio, updateDuration) >
            _MAX_DAILY_PRICE_RATIO_UPDATE_RATE
        ) {
            revert PriceRatioUpdateTooFast();
        }
    }

    /// @inheritdoc IReClammPool
    function stopPriceRatioUpdate() external onlyWhenInitialized onlySwapFeeManagerOrGovernance(address(this)) {
        uint256[] memory balancesScaled18 = _updateVirtualBalances();

        PriceRatioState memory priceRatioState = _priceRatioState;
        if (priceRatioState.priceRatioUpdateEndTime < block.timestamp) {
            revert PriceRatioNotUpdating();
        }

        // Compute the current price ratio inline, avoiding a second Vault rate fetch.
        uint256 currentPriceRatio = ReClammMath.computePriceRatio(
            balancesScaled18,
            _lastVirtualBalanceA,
            _lastVirtualBalanceB
        );

        _startPriceRatioUpdate(currentPriceRatio, block.timestamp, block.timestamp, currentPriceRatio);
    }

    /// @inheritdoc IReClammPool
    function setDailyPriceShiftExponent(
        uint256 newDailyPriceShiftExponent
    )
        external
        onlyWhenInitialized
        onlyWhenVaultIsLocked
        onlySwapFeeManagerOrGovernance(address(this))
        returns (uint256)
    {
        // Update virtual balances before updating the daily price shift exponent.
        // NOTE: increasing the shift rate increases the pool's exposure to round-trip repricing extraction.
        // Ensure the swap fee is at least `shift_rate_pct * 0.0002%` to maintain a safe breakeven time.
        // See the interface NatSpec for the full analysis.
        return _setDailyPriceShiftExponentAndUpdateVirtualBalances(newDailyPriceShiftExponent);
    }

    /// @inheritdoc IReClammPool
    function setCenterednessMargin(
        uint256 newCenterednessMargin
    ) external onlyWhenInitialized onlyWhenVaultIsLocked onlySwapFeeManagerOrGovernance(address(this)) {
        uint256[] memory balancesScaled18 = _updateVirtualBalances();

        // Virtual balances are updated in the call above, so we can just read last virtual balances here.
        (uint256 centeredness, ) = ReClammMath.computeCenteredness(
            balancesScaled18,
            _lastVirtualBalanceA,
            _lastVirtualBalanceB
        );

        // The current margin must place the pool within the target range, to prevent setting a margin that would
        // immediately place the pool outside of the target range. This is important because an excessively high margin
        // could be used maliciously to manipulate the pool price by forcing it to stay within an excessively tight
        // range. The new margin must also not be higher than the current centeredness, to prevent similar manipulation.
        // It is possible to bypass this check with settled swaps before and after setting the new margin;
        // this is a best-effort check to prevent accidental misconfigurations.
        require(centeredness >= _centerednessMargin && centeredness >= newCenterednessMargin, PoolOutsideTargetRange());

        _setCenterednessMargin(newCenterednessMargin);
    }

    /********************************************************
                        Internal Helpers
    ********************************************************/

    function _computeCurrentVirtualBalances(
        uint256[] memory balancesScaled18
    ) internal view returns (uint256 currentVirtualBalanceA, uint256 currentVirtualBalanceB, bool changed) {
        (currentVirtualBalanceA, currentVirtualBalanceB, changed) = ReClammMath.computeCurrentVirtualBalances(
            balancesScaled18,
            _lastVirtualBalanceA,
            _lastVirtualBalanceB,
            _dailyPriceShiftBase,
            _lastTimestamp,
            _centerednessMargin,
            _priceRatioState
        );
    }

    function _setLastVirtualBalances(uint256 virtualBalanceA, uint256 virtualBalanceB) internal {
        _lastVirtualBalanceA = virtualBalanceA.toUint128();
        _lastVirtualBalanceB = virtualBalanceB.toUint128();

        emit VirtualBalancesUpdated(virtualBalanceA, virtualBalanceB);

        _vault.emitAuxiliaryEvent("VirtualBalancesUpdated", abi.encode(virtualBalanceA, virtualBalanceB));
    }

    /**
     * @dev `precomputedStartPriceRatio` is read only when the pool is already initialized. The runtime callers
     * (`startPriceRatioUpdate`, `stopPriceRatioUpdate`) compute it from the balances `_updateVirtualBalances` returned
     * and the virtual balances it wrote, so the captured starting ratio stays consistent with the inputs that drove
     * the virtual balance update without a second Vault rate fetch. Init callers (`onBeforeInitialize`,
     * `ReClammPoolMock.reInitialize`) pass 0 because the not-initialized branch sources the start fourth root from
     * `endPriceRatio` instead.
     */
    function _startPriceRatioUpdate(
        uint256 endPriceRatio,
        uint256 priceRatioUpdateStartTime,
        uint256 priceRatioUpdateEndTime,
        uint256 precomputedStartPriceRatio
    ) internal {
        if (priceRatioUpdateStartTime > priceRatioUpdateEndTime || priceRatioUpdateStartTime < block.timestamp) {
            revert InvalidStartTime();
        }

        PriceRatioState memory priceRatioState = _priceRatioState;

        uint256 endFourthRootPriceRatio = ReClammMath.fourthRootScaled18(endPriceRatio);

        uint256 startFourthRootPriceRatio;
        if (_vault.isPoolInitialized(address(this))) {
            startFourthRootPriceRatio = ReClammMath.fourthRootScaled18(precomputedStartPriceRatio);
        } else {
            startFourthRootPriceRatio = endFourthRootPriceRatio;
        }

        priceRatioState.startFourthRootPriceRatio = startFourthRootPriceRatio.toUint96();
        priceRatioState.endFourthRootPriceRatio = endFourthRootPriceRatio.toUint96();
        priceRatioState.priceRatioUpdateStartTime = priceRatioUpdateStartTime.toUint32();
        priceRatioState.priceRatioUpdateEndTime = priceRatioUpdateEndTime.toUint32();

        _priceRatioState = priceRatioState;

        emit PriceRatioStateUpdated(
            startFourthRootPriceRatio,
            endFourthRootPriceRatio,
            priceRatioUpdateStartTime,
            priceRatioUpdateEndTime
        );

        _vault.emitAuxiliaryEvent(
            "PriceRatioStateUpdated",
            abi.encode(
                startFourthRootPriceRatio,
                endFourthRootPriceRatio,
                priceRatioUpdateStartTime,
                priceRatioUpdateEndTime
            )
        );
    }

    /**
     * @notice Computes the effective daily price ratio update rate for a given start/end ratio and duration.
     * @dev The rate is exponential: `(max(end, start) / min(end, start))^(1 day / updateDuration)`.
     * All inputs and the return value are 18-decimal fixed point.
     *
     * @param startPriceRatio The price ratio at the start of the update
     * @param endPriceRatio The price ratio at the end of the update
     * @param updateDuration The duration of the update in seconds
     * @return The effective daily price ratio change factor (>= FP(1))
     */
    function _computeDailyPriceRatioUpdateRate(
        uint256 startPriceRatio,
        uint256 endPriceRatio,
        uint256 updateDuration
    ) internal pure returns (uint256) {
        uint256 priceRatioMultiple = endPriceRatio > startPriceRatio
            ? endPriceRatio.divUp(startPriceRatio)
            : startPriceRatio.divUp(endPriceRatio);
        uint256 exponent = FixedPoint.divUp(1 days, updateDuration);
        return priceRatioMultiple.powUp(exponent);
    }

    /// Using the pool balances to update the virtual balances is dangerous with an unlocked vault, since the balances
    /// are manipulable.
    function _setDailyPriceShiftExponentAndUpdateVirtualBalances(
        uint256 dailyPriceShiftExponent
    ) internal returns (uint256) {
        // Update virtual balances with current daily price shift exponent.
        _updateVirtualBalances();

        // Update the price shift exponent.
        return _setDailyPriceShiftExponent(dailyPriceShiftExponent);
    }

    function _setDailyPriceShiftExponent(uint256 dailyPriceShiftExponent) internal returns (uint256) {
        ReClammPoolFactoryLib.validateDailyPriceShiftExponent(dailyPriceShiftExponent);

        uint256 dailyPriceShiftBase = dailyPriceShiftExponent.toDailyPriceShiftBase();
        // There might be precision loss when adjusting to the internal representation, so we need to
        // convert back to the external representation to emit the event.
        dailyPriceShiftExponent = dailyPriceShiftBase.toDailyPriceShiftExponent();

        _dailyPriceShiftBase = dailyPriceShiftBase.toUint128();

        emit DailyPriceShiftExponentUpdated(dailyPriceShiftExponent, dailyPriceShiftBase);

        _vault.emitAuxiliaryEvent(
            "DailyPriceShiftExponentUpdated",
            abi.encode(dailyPriceShiftExponent, dailyPriceShiftBase)
        );

        return dailyPriceShiftExponent;
    }

    /**
     * @notice Sets the centeredness margin when the pool is created.
     * @param centerednessMargin The new centerednessMargin value, which must be within the target range
     */
    function _setCenterednessMargin(uint256 centerednessMargin) internal {
        ReClammPoolFactoryLib.validateCenterednessMargin(centerednessMargin);

        // Straight cast is safe since the margin is validated above (and tests ensure the margins fit in uint64).
        _centerednessMargin = uint64(centerednessMargin);

        emit CenterednessMarginUpdated(centerednessMargin);

        _vault.emitAuxiliaryEvent("CenterednessMarginUpdated", abi.encode(centerednessMargin));
    }

    function _updateVirtualBalances() internal returns (uint256[] memory balancesScaled18) {
        uint256 currentVirtualBalanceA;
        uint256 currentVirtualBalanceB;
        bool changed;

        (balancesScaled18, currentVirtualBalanceA, currentVirtualBalanceB, changed) = _getRealAndVirtualBalances();

        if (changed) {
            _setLastVirtualBalances(currentVirtualBalanceA, currentVirtualBalanceB);
        }
        _updateTimestamp();
    }

    // Updates the last timestamp to the current timestamp.
    function _updateTimestamp() internal {
        uint32 lastTimestamp32 = block.timestamp.toUint32();
        _lastTimestamp = lastTimestamp32;

        emit LastTimestampUpdated(lastTimestamp32);

        _vault.emitAuxiliaryEvent("LastTimestampUpdated", abi.encode(lastTimestamp32));
    }

    /**
     * @notice Computes the current price ratio using live balances and time-adjusted virtual balances.
     * @return The current price ratio (maxPrice / minPrice) as an 18-decimal FP value
     */
    function _computeCurrentPriceRatio() internal view returns (uint256) {
        (
            uint256[] memory balancesScaled18,
            uint256 currentVirtualBalanceA,
            uint256 currentVirtualBalanceB,

        ) = _getRealAndVirtualBalances();

        return ReClammMath.computePriceRatio(balancesScaled18, currentVirtualBalanceA, currentVirtualBalanceB);
    }

    function _getLastVirtualBalances() internal view returns (uint256[] memory) {
        uint256[] memory lastVirtualBalances = new uint256[](2);
        lastVirtualBalances[a] = _lastVirtualBalanceA;
        lastVirtualBalances[b] = _lastVirtualBalanceB;

        return lastVirtualBalances;
    }
}

contracts/ReClammPoolFactory.sol.content:
// SPDX-License-Identifier: GPL-3.0-or-later

pragma solidity ^0.8.24;

import { SafeCast } from "@openzeppelin/contracts/utils/math/SafeCast.sol";
// solhint-disable-next-line no-unused-import
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";

import { IPoolVersion } from "@balancer-labs/v3-interfaces/contracts/solidity-utils/helpers/IPoolVersion.sol";
import { IVault } from "@balancer-labs/v3-interfaces/contracts/vault/IVault.sol";
import {
    TokenConfig,
    PoolRoleAccounts,
    LiquidityManagement
} from "@balancer-labs/v3-interfaces/contracts/vault/VaultTypes.sol";

import { BasePoolFactory } from "@balancer-labs/v3-pool-utils/contracts/BasePoolFactory.sol";
import { Version } from "@balancer-labs/v3-solidity-utils/contracts/helpers/Version.sol";

import { ReClammPoolFactoryLib, ReClammPriceParams } from "./lib/ReClammPoolFactoryLib.sol";
import { ReClammPoolParams } from "./interfaces/IReClammPool.sol";
import { ReClammPool } from "./ReClammPool.sol";
import { ReClammPoolHelper } from "./ReClammPoolHelper.sol";

/// @notice ReClammPool factory.
contract ReClammPoolFactory is IPoolVersion, BasePoolFactory, Version {
    using SafeCast for uint256;

    // solhint-disable-next-line immutable-vars-naming
    ReClammPoolHelper public immutable reClammPoolHelper;

    string private _poolVersion;

    /// @notice Thrown if the provided helper was not deployed with the same Vault as the factory.
    error WrongHelperDeployment();

    constructor(
        IVault vault,
        ReClammPoolHelper helper,
        uint32 pauseWindowDuration,
        string memory factoryVersion,
        string memory poolVersion
    ) BasePoolFactory(vault, pauseWindowDuration, type(ReClammPool).creationCode) Version(factoryVersion) {
        require(address(helper.vault()) == address(getVault()), WrongHelperDeployment());

        reClammPoolHelper = helper;
        _poolVersion = poolVersion;
    }

    /// @inheritdoc IPoolVersion
    function getPoolVersion() external view returns (string memory) {
        return _poolVersion;
    }

    /**
     * @notice Deploys a new `ReClammPool`.
     * @param name The name of the pool
     * @param symbol The symbol of the pool
     * @param tokens An array of descriptors for the tokens the pool will manage
     * @param roleAccounts Addresses the Vault will allow to change certain pool settings
     * @param swapFeePercentage Initial swap fee percentage
     * @param priceParams Initial min, max and target prices; flags indicating whether token prices incorporate rates
     * @param dailyPriceShiftExponent Virtual balances will change by 2^(dailyPriceShiftExponent) per day
     * @param centerednessMargin How far the price can be from the center before the price range starts to move
     * @param salt The salt value that will be passed to deployment
     */
    function create(
        string memory name,
        string memory symbol,
        TokenConfig[] memory tokens,
        PoolRoleAccounts memory roleAccounts,
        uint256 swapFeePercentage,
        ReClammPriceParams memory priceParams,
        uint256 dailyPriceShiftExponent,
        uint256 centerednessMargin,
        bytes32 salt
    ) external returns (address pool) {
        ReClammPoolFactoryLib.validateTokenConfig(tokens, priceParams);

        LiquidityManagement memory liquidityManagement = getDefaultLiquidityManagement();
        liquidityManagement.enableDonation = false;
        liquidityManagement.disableUnbalancedLiquidity = true;

        ReClammPoolParams memory poolParams = ReClammPoolParams({
            name: name,
            symbol: symbol,
            version: _poolVersion,
            initialMinPrice: priceParams.initialMinPrice,
            initialMaxPrice: priceParams.initialMaxPrice,
            initialTargetPrice: priceParams.initialTargetPrice,
            tokenAPriceIncludesRate: priceParams.tokenAPriceIncludesRate,
            tokenBPriceIncludesRate: priceParams.tokenBPriceIncludesRate,
            dailyPriceShiftExponent: dailyPriceShiftExponent,
            centerednessMargin: centerednessMargin.toUint64()
        });

        ReClammPoolFactoryLib.validatePoolParams(poolParams);

        pool = _create(abi.encode(poolParams, getVault(), reClammPoolHelper), salt);

        _registerPoolWithVault(
            pool,
            tokens,
            swapFeePercentage,
            false, // not exempt from protocol fees
            roleAccounts,
            pool, // The pool is the hook
            liquidityManagement
        );
    }
}

contracts/ReClammPoolHelper.sol.content:
// SPDX-License-Identifier: GPL-3.0-or-later

pragma solidity ^0.8.24;

import { IERC20Metadata } from "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";

import { IVaultErrors } from "@balancer-labs/v3-interfaces/contracts/vault/IVaultErrors.sol";
import { IVault } from "@balancer-labs/v3-interfaces/contracts/vault/IVault.sol";
import "@balancer-labs/v3-interfaces/contracts/vault/VaultTypes.sol";

import { ScalingHelpers } from "@balancer-labs/v3-solidity-utils/contracts/helpers/ScalingHelpers.sol";
import { FixedPoint } from "@balancer-labs/v3-solidity-utils/contracts/math/FixedPoint.sol";

import { ReClammPoolImmutableData, IReClammPool } from "./interfaces/IReClammPool.sol";
import { ReClammMath, a, b } from "./lib/ReClammMath.sol";

/// @notice Stateless helper contract to perform accessory computations for the `ReClammPool`.
contract ReClammPoolHelper {
    using FixedPoint for uint256;
    using ScalingHelpers for *;

    // This represents the maximum deviation from the ideal state (i.e., at target price and near centered) after
    // initialization, to prevent arbitration losses.
    uint256 public constant BALANCE_RATIO_AND_PRICE_TOLERANCE = 0.01e16; // 0.01%

    uint256 internal constant _MAX_TOKEN_DECIMALS = 18;

    // solhint-disable-next-line immutable-vars-naming
    IVault public immutable vault;

    constructor(IVault vault_) {
        vault = vault_;
    }

    function computeInitialBalancesRaw(
        IReClammPool pool,
        IERC20 referenceToken,
        uint256 referenceAmountInRaw
    ) external view returns (uint256[] memory initialBalancesRaw) {
        IERC20[] memory tokens = vault.getPoolTokens(address(pool));

        (uint256 referenceTokenIdx, uint256 otherTokenIdx) = address(tokens[a]) == address(referenceToken)
            ? (a, b)
            : (b, a);

        if (referenceTokenIdx == b && address(referenceToken) != address(tokens[b])) {
            revert IVaultErrors.InvalidToken();
        }

        (uint256 rateA, uint256 rateB) = _getTokenRates(address(pool));
        uint256 balanceRatioScaled18 = _computeInitialBalanceRatioScaled18(IReClammPool(pool), rateA, rateB);
        (uint256 rateReferenceToken, uint256 rateOtherToken) = address(tokens[a]) == address(referenceToken)
            ? (rateA, rateB)
            : (rateB, rateA);

        uint8 decimalsReferenceToken = IERC20Metadata(address(tokens[referenceTokenIdx])).decimals();
        uint8 decimalsOtherToken = IERC20Metadata(address(tokens[otherTokenIdx])).decimals();

        uint256 referenceAmountInScaled18 = referenceAmountInRaw.toScaled18ApplyRateRoundDown(
            10 ** (_MAX_TOKEN_DECIMALS - decimalsReferenceToken),
            rateReferenceToken
        );

        // Since the ratio is defined as b/a, multiply if we're given a, and divide if we're given b.
        // If the theoretical virtual balances were a=50 and b=100, then the ratio would be 100/50 = 2.
        // If we're given 100 a tokens, b = a * 2 = 200. If we're given 200 b tokens, a = b / 2 = 100.
        initialBalancesRaw = new uint256[](2);
        initialBalancesRaw[referenceTokenIdx] = referenceAmountInRaw;

        function(uint256, uint256) pure returns (uint256) _mulOrDiv = referenceTokenIdx == a
            ? FixedPoint.mulDown
            : FixedPoint.divDown;
        initialBalancesRaw[otherTokenIdx] = _mulOrDiv(referenceAmountInScaled18, balanceRatioScaled18)
            .toRawUndoRateRoundDown(10 ** (_MAX_TOKEN_DECIMALS - decimalsOtherToken), rateOtherToken);
    }

    function computeInitialBalanceRatioScaled18(
        IReClammPool pool,
        uint256 rateA,
        uint256 rateB
    ) external view returns (uint256) {
        return _computeInitialBalanceRatioScaled18(pool, rateA, rateB);
    }

    function _computeInitialBalanceRatioScaled18(
        IReClammPool pool,
        uint256 rateA,
        uint256 rateB
    ) internal view returns (uint256) {
        (
            uint256 minPriceScaled18,
            uint256 maxPriceScaled18,
            uint256 targetPriceScaled18
        ) = _getPriceSettingsAdjustedByRates(pool, rateA, rateB);

        (uint256[] memory theoreticalBalancesScaled18, , , ) = ReClammMath.computeTheoreticalPriceRatioAndBalances(
            minPriceScaled18,
            maxPriceScaled18,
            targetPriceScaled18
        );

        return theoreticalBalancesScaled18[b].divDown(theoreticalBalancesScaled18[a]);
    }

    struct InitializeLocals {
        uint256 rateA;
        uint256 rateB;
        uint256 minPriceScaled18;
        uint256 maxPriceScaled18;
        uint256 targetPriceScaled18;
        uint256[] theoreticalBalances;
        uint256 theoreticalVirtualBalanceA;
        uint256 theoreticalVirtualBalanceB;
        uint256 priceRatio;
    }

    /**
     * @notice Compute the initialization amounts, given a reference token and amount.
     * @dev Intended to be called by a ReClamm pool. The helper treats `msg.sender` as the pool and reads pool
     * configuration from it. The pool pre-fetches token rates and passes them in so the helper's balance-ratio and
     * price-tolerance checks use the same rate values throughout the initialization call.
     *
     * @param balancesScaled18 Initial pool balances (decimal scaling and rates already applied)
     * @param rateA Rate of token A (in 18-decimal FP); pass `FixedPoint.ONE` for tokens without a rate
     * @param rateB Rate of token B (in 18-decimal FP); pass `FixedPoint.ONE` for tokens without a rate
     */
    function computeInitialVirtualBalancesAndRatio(
        uint256[] calldata balancesScaled18,
        uint256 rateA,
        uint256 rateB
    ) external view returns (uint256, uint256, uint256) {
        IReClammPool pool = IReClammPool(msg.sender);
        InitializeLocals memory locals;
        locals.rateA = rateA;
        locals.rateB = rateB;

        (
            locals.minPriceScaled18,
            locals.maxPriceScaled18,
            locals.targetPriceScaled18
        ) = _getPriceSettingsAdjustedByRates(pool, locals.rateA, locals.rateB);

        (
            locals.theoreticalBalances,
            locals.theoreticalVirtualBalanceA,
            locals.theoreticalVirtualBalanceB,
            locals.priceRatio
        ) = ReClammMath.computeTheoreticalPriceRatioAndBalances(
            locals.minPriceScaled18,
            locals.maxPriceScaled18,
            locals.targetPriceScaled18
        );

        _checkInitializationBalanceRatio(balancesScaled18, locals.theoreticalBalances);

        uint256 scale = balancesScaled18[a].divDown(locals.theoreticalBalances[a]);

        uint256 virtualBalanceA = locals.theoreticalVirtualBalanceA.mulDown(scale);
        uint256 virtualBalanceB = locals.theoreticalVirtualBalanceB.mulDown(scale);

        _checkInitializationPrices(
            balancesScaled18,
            locals.minPriceScaled18,
            locals.maxPriceScaled18,
            locals.targetPriceScaled18,
            virtualBalanceA,
            virtualBalanceB
        );

        return (virtualBalanceA, virtualBalanceB, locals.priceRatio);
    }

    function getTokenRates(address pool) external view returns (uint256 rateA, uint256 rateB) {
        return _getTokenRates(pool);
    }

    function _getTokenRates(address pool) internal view returns (uint256 rateA, uint256 rateB) {
        (, TokenInfo[] memory tokenInfo, , ) = vault.getPoolTokenInfo(pool);

        rateA = _getTokenRate(tokenInfo[a]);
        rateB = _getTokenRate(tokenInfo[b]);
    }

    function _getTokenRate(TokenInfo memory tokenInfo) internal view returns (uint256) {
        return tokenInfo.tokenType == TokenType.WITH_RATE ? tokenInfo.rateProvider.getRate() : FixedPoint.ONE;
    }

    function _getPriceSettingsAdjustedByRates(
        IReClammPool pool,
        uint256 rateA,
        uint256 rateB
    ) internal view returns (uint256 minPrice, uint256 maxPrice, uint256 targetPrice) {
        ReClammPoolImmutableData memory data = pool.getReClammPoolImmutableData();

        rateA = data.tokenAPriceIncludesRate ? FixedPoint.ONE : rateA;
        rateB = data.tokenBPriceIncludesRate ? FixedPoint.ONE : rateB;

        // Example: a pool waUSDC/waWETH, where the price is given in terms of the underlying tokens.
        // Consider a USDC/ETH pool where the price is 2000. Token A is ETH (waWETH); token B is USDC (waUSDC).
        // If waUSDC has a rate of 2 (1 waUSDC = 2 USDC), the price of waUSDC/ETH is 1000, which is
        // obtained by dividing the price by the rate of waUSDC, which is token B.
        // Now, if the rate of waWETH is 1.5 (1 waWETH = 1.5 ETH), waUSDC/waWETH = 1500, which is
        // obtained by multiplying the price by the rate of waWETH, which is token A.
        // On the other hand, spot prices are computed using live balances which always contain the rates, so
        // we apply the inverse here (i.e. multiply by rate B, divide by rate A) to undo the effect.
        minPrice = (data.initialMinPrice * rateB) / rateA;
        maxPrice = (data.initialMaxPrice * rateB) / rateA;
        targetPrice = (data.initialTargetPrice * rateB) / rateA;
    }

    function checkInitializationBalanceRatio(
        uint256[] calldata balancesScaled18,
        uint256[] memory theoreticalBalances
    ) external pure {
        return _checkInitializationBalanceRatio(balancesScaled18, theoreticalBalances);
    }

    /// @dev Checks that the current balance ratio is within the initialization balance ratio tolerance.
    function _checkInitializationBalanceRatio(
        uint256[] calldata balancesScaled18,
        uint256[] memory theoreticalBalances
    ) internal pure {
        uint256 realBalanceRatio = balancesScaled18[b].divDown(balancesScaled18[a]);
        uint256 theoreticalBalanceRatio = theoreticalBalances[b].divDown(theoreticalBalances[a]);

        uint256 ratioLowerBound = theoreticalBalanceRatio.mulDown(FixedPoint.ONE - BALANCE_RATIO_AND_PRICE_TOLERANCE);
        uint256 ratioUpperBound = theoreticalBalanceRatio.mulDown(FixedPoint.ONE + BALANCE_RATIO_AND_PRICE_TOLERANCE);

        if (realBalanceRatio < ratioLowerBound || realBalanceRatio > ratioUpperBound) {
            revert IReClammPool.BalanceRatioExceedsTolerance();
        }
    }

    /**
     * @dev Checks that the current spot price is within the initialization tolerance of the price target, and that
     * the total price range after initialization (i.e., with real balances) corresponds closely enough to the desired
     * initial price range set on deployment.
     */
    function _checkInitializationPrices(
        uint256[] calldata balancesScaled18,
        uint256 minPrice,
        uint256 maxPrice,
        uint256 targetPrice,
        uint256 virtualBalanceA,
        uint256 virtualBalanceB
    ) internal pure {
        // Compare current spot price with initialization target price.
        uint256 spotPrice = (balancesScaled18[b] + virtualBalanceB).divDown(balancesScaled18[a] + virtualBalanceA);
        _comparePrice(spotPrice, targetPrice);

        // Compare current min and max prices with initialization values.
        (uint256 currentMinPrice, uint256 currentMaxPrice) = ReClammMath.computePriceRange(
            balancesScaled18,
            virtualBalanceA,
            virtualBalanceB
        );
        _comparePrice(currentMinPrice, minPrice);
        _comparePrice(currentMaxPrice, maxPrice);
    }

    function _comparePrice(uint256 currentPrice, uint256 initializationPrice) internal pure {
        uint256 priceLowerBound = initializationPrice.mulDown(FixedPoint.ONE - BALANCE_RATIO_AND_PRICE_TOLERANCE);
        uint256 priceUpperBound = initializationPrice.mulDown(FixedPoint.ONE + BALANCE_RATIO_AND_PRICE_TOLERANCE);

        if (currentPrice < priceLowerBound || currentPrice > priceUpperBound) {
            revert IReClammPool.WrongInitializationPrices();
        }
    }

    /**
     * @notice Computes the current spot price of token B in terms of token A: i.e., how many token A units are
     * required to purchase one token B, or equivalently, how many token A units you receive per token B sold.
     * @dev The price is expressed as token/token (e.g., wstETH/USDC), not underlying/underlying (e.g. ETH/USDC).
     * This matches what a swapper experiences: if this function returns 3000, then swapping 3000 USDC yields
     * approximately 1 wstETH. Internally, the spot price is derived from live (rate-scaled) balances plus virtual
     * balances, then adjusted by the ratio of token rates (rateA / rateB) to convert from the underlying/underlying
     * price that the AMM math operates on to the token/token price that callers expect. For pools with no rate
     * providers (or rate = 1), the two are identical.
     *
     * Note that `initialTargetPrice` may have been specified in either token or underlying terms depending on
     * `tokenAPriceIncludesRate` / `tokenBPriceIncludesRate`, so it cannot in general be directly compared to this
     * return value.
     *
     * It is meant to be called off-chain. Given the nature of the internal pool math (particularly when virtual
     * balances are shifting), this function **cannot be used as a price oracle**.
     *
     * @param pool The address of the pool
     * @return currentSpotPrice Spot price at the current pool state (real and virtual balances), in token/token terms
     */
    function computeCurrentSpotPrice(address pool) external view returns (uint256) {
        (, uint256[] memory tokenRates) = vault.getPoolTokenRates(pool);
        uint256[] memory balancesScaled18 = vault.getCurrentLiveBalances(pool);
        (uint256 currentVirtualBalanceA, uint256 currentVirtualBalanceB, ) = IReClammPool(pool)
            .computeCurrentVirtualBalances();

        // Undo rate effects to return the spot price in terms of actual token amounts.
        return
            ((balancesScaled18[b] + currentVirtualBalanceB) * tokenRates[a]) /
            (balancesScaled18[a] + currentVirtualBalanceA).mulUp(tokenRates[b]);
    }
}
